proccessPendingEnrollments();
function proccessPendingEnrollments() {
    try {
        logger.error("Processing Pending Enrollments");
        var response = openidm.read('endpoint/provisionPendingEnrollments', {});
        logger.error("Response is "+ response)
        if(response){
            logger.error("Pending Enrollments Processed Successfully" + JSON.stringify(response));
        }


    } catch (error) {
        logger.error("Error in Processing Pending Enrollments: " + error);
    }
}
